import { defineConfig } from '@playwright/test';
import fs from 'fs';
import path from 'path';

function loadDotEnvFile(filePath: string, opts: { override: boolean }): void {
  if (!fs.existsSync(filePath)) return;

  const content = fs.readFileSync(filePath, 'utf8');
  for (const rawLine of content.split(/\r?\n/)) {
    const line = rawLine.trim();
    if (!line || line.startsWith('#')) continue;

    const eqIndex = line.indexOf('=');
    if (eqIndex <= 0) continue;

    const key = line.slice(0, eqIndex).trim();
    let value = line.slice(eqIndex + 1).trim();

    if ((value.startsWith('"') && value.endsWith('"')) || (value.startsWith("'") && value.endsWith("'"))) {
      value = value.slice(1, -1);
    }

    if (opts.override || process.env[key] === undefined) {
      process.env[key] = value;
    }
  }
}

// Load environment variables based on NODE_ENV
const isStaging = process.env.NODE_ENV === 'staging';
const rootDir = process.cwd();

// Base .env (se existir)
const baseEnvPath = path.resolve(rootDir, '.env');
if (fs.existsSync(baseEnvPath)) {
  loadDotEnvFile(baseEnvPath, { override: false });
}

// Override por ambiente
if (isStaging) {
  const stagingEnvPath = path.resolve(rootDir, '.env.staging');
  if (fs.existsSync(stagingEnvPath)) {
    loadDotEnvFile(stagingEnvPath, { override: true });
  }
} else {
  const rootLocalEnvPath = path.resolve(rootDir, '.env.local');
  const appLocalEnvPath = path.resolve(rootDir, 'estudio_ia_videos/.env.local');

  if (fs.existsSync(rootLocalEnvPath)) {
    loadDotEnvFile(rootLocalEnvPath, { override: true });
  } else if (fs.existsSync(appLocalEnvPath)) {
    loadDotEnvFile(appLocalEnvPath, { override: true });
  }
}

export default defineConfig({
  testDir: 'estudio_ia_videos/src/__tests__/e2e',
  testMatch: ['**/*.spec.ts'],
  testIgnore: ['**/_archive/**', '**/node_modules/**'],
  timeout: 60000,
  retries: process.env.CI ? 1 : 0,
  use: {
    baseURL: process.env.E2E_BASE_URL || process.env.NEXT_PUBLIC_APP_URL || 'http://localhost:3000',
    trace: 'on-first-retry',
    ignoreHTTPSErrors: true
  },
  webServer: (process.env.E2E_SKIP_SERVER || isStaging) ? undefined : {
    command: 'cd estudio_ia_videos && npm run dev',
    url: 'http://localhost:3000',
    reuseExistingServer: !process.env.CI,
    timeout: 90000
  },
  reporter: [ ['list'], ['html', { outputFolder: 'evidencias/playwright-report' }] ]
});